def assign_freq(tuples_list):
    result = []
    for tuple_in_list in tuples_list:
        counts = {}
        for item in tuple_in_list:
            counts[item] = counts.get(item, 0) + 1
        new_tuple = tuple([item + (counts[item],) for item in counts])
        result.append(new_tuple)
    return result

